import React, { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { supabase } from '../../lib/supabaseClient'
import { 
  UserIcon, 
  UsersIcon, 
  CalendarIcon, 
  ShoppingBagIcon,
  PlusIcon
} from '@heroicons/react/24/outline'
import { IMAGES } from '../../constants/images'

export const Dashboard: React.FC = () => {
  const [user, setUser] = useState<any>(null)
  const [profile, setProfile] = useState<any>(null)
  const [upcomingSessions, setUpcomingSessions] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    // Get current user
    const { data: { user: currentUser } } = await supabase.auth.getUser()
    setUser(currentUser)

    // Get profile
    const { data: profileData } = await supabase
      .from('users')
      .select('*')
      .eq('id', currentUser?.id)
      .single()
    setProfile(profileData)

    // Get upcoming sessions
    const today = new Date().toISOString().split('T')[0]
    const { data: sessions } = await supabase
      .from('sports_sessions')
      .select('*')
      .gte('session_date', today)
      .order('session_date', { ascending: true })
      .limit(3)
    setUpcomingSessions(sessions || [])
    setLoading(false)
  }

  if (loading) return <div style={{ padding: '40px', color: '#888' }}>Loading...</div>

  const cards = [
    { title: 'Find Players', icon: UsersIcon, path: '/find-players', desc: 'Search & match with players' },
    { title: 'Create Session', icon: PlusIcon, path: '/create-session', desc: 'Organise a sports session' },
    { title: 'Browse Sessions', icon: CalendarIcon, path: '/browse-sessions', desc: 'Find & join sessions' },
    { title: 'Marketplace', icon: ShoppingBagIcon, path: '/marketplace', desc: 'Buy & sell equipment' },
  ]

  return (
    <div style={{
  minHeight: '100vh',
  background: `url(${IMAGES.dashboardBg}) center/cover no-repeat`,
  backgroundColor: '#0a0a0a',
  color: 'white',
  padding: '24px',
  position: 'relative'
}}>
  {/* Dark Overlay */}
  <div style={{
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    background: 'rgba(0,0,0,0.65)',
    zIndex: 0
  }} />
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        {/* Welcome */}
        <div style={{ marginBottom: '30px' }}>
          <h1 style={{ color: '#FFD700', fontSize: '28px', fontWeight: 'bold' }}>
            Welcome back, {profile?.full_name?.split(' ')[0] || 'Player'}! 👋
          </h1>
          <p style={{ color: '#888' }}>What would you like to do today?</p>
        </div>

        {/* Stats */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: '16px',
          marginBottom: '30px'
        }}>
          {[
            { label: 'Sessions Joined', value: '12' },
            { label: 'Players Found', value: '5' },
            { label: 'Listings', value: '3' },
            { label: 'Posts', value: '8' }
          ].map((stat, i) => (
            <div key={i} style={{
              background: '#0d0d0d',
              border: '1px solid #c8a20020',
              borderRadius: '12px',
              padding: '16px',
              textAlign: 'center'
            }}>
              <div style={{ color: '#FFD700', fontSize: '24px', fontWeight: 'bold' }}>{stat.value}</div>
              <div style={{ color: '#666', fontSize: '13px' }}>{stat.label}</div>
            </div>
          ))}
        </div>

        {/* Cards */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: '16px',
          marginBottom: '30px'
        }}>
          {cards.map((card) => (
            <Link
              key={card.title}
              to={card.path}
              style={{
                background: '#0d0d0d',
                border: '1px solid #c8a20020',
                borderRadius: '12px',
                padding: '24px',
                textAlign: 'center',
                textDecoration: 'none',
                color: 'white',
                transition: 'all 0.3s'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = '#c8a200'
                e.currentTarget.style.transform = 'scale(1.02)'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = '#c8a20020'
                e.currentTarget.style.transform = 'scale(1)'
              }}
            >
              <card.icon style={{ width: '32px', height: '32px', color: '#FFD700', margin: '0 auto 12px' }} />
              <h3 style={{ fontSize: '14px', fontWeight: 'bold', marginBottom: '4px' }}>{card.title}</h3>
              <p style={{ color: '#666', fontSize: '12px' }}>{card.desc}</p>
            </Link>
          ))}
        </div>

        {/* Upcoming Sessions */}
        <div>
          <h2 style={{ color: '#FFD700', fontSize: '18px', marginBottom: '12px' }}>Upcoming Sessions</h2>
          {upcomingSessions.length === 0 ? (
            <div style={{
              background: '#0d0d0d',
              border: '1px solid #c8a20020',
              borderRadius: '12px',
              padding: '40px',
              textAlign: 'center',
              color: '#666'
            }}>
              No upcoming sessions. <Link to="/create-session" style={{ color: '#c8a200' }}>Create one!</Link>
            </div>
          ) : (
            upcomingSessions.map((session) => (
              <div key={session.id} style={{
                background: '#0d0d0d',
                border: '1px solid #c8a20020',
                borderRadius: '12px',
                padding: '16px',
                marginBottom: '8px',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
              }}>
                <div>
                  <h3 style={{ fontWeight: 'bold' }}>{session.sport_type}</h3>
                  <p style={{ color: '#888', fontSize: '13px' }}>
                    {session.location} • {session.session_date}
                  </p>
                </div>
                <Link
                  to={`/session/${session.id}`}
                  style={{
                    background: '#c8a200',
                    color: '#0a0a0a',
                    padding: '6px 16px',
                    borderRadius: '8px',
                    textDecoration: 'none',
                    fontWeight: 'bold',
                    fontSize: '13px'
                  }}
                >
                  View
                </Link>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  )
}
